4. 测试用例设计与数据准备
4.1 测试用例设计技巧
有效的测试用例设计应该覆盖正常流程、边界条件和异常场景[ref_4]。采用等价类划分和边界值分析等方法：
// 边界值测试用例示例

public class BoundaryTest {
    @Test
    public void testAgeBoundary() {
        // 测试年龄边界值

        assertTrue(isValidAge(0));   // 下边界

        assertTrue(isValidAge(1));   // 边界+1

        assertTrue(isValidAge(99));  // 上边界-1

        assertTrue(isValidAge(100)); // 上边界

        assertFalse(isValidAge(-1)); // 边界外

        assertFalse(isValidAge(101)); // 边界外

    }
}
